package com.ecoPedal.backend.repository;import com.ecoPedal.backend.entity.AdminActionLog;import com.ecoPedal.backend.entity.Administrateur;import org.springframework.data.jpa.repository.JpaRepository;import org.springframework.stereotype.Repository;import java.util.List;@Repositorypublic interface AdminActionLogRepository extends JpaRepository<AdminActionLog, Long> {    List<AdminActionLog> findByAdministrateurOrderByDateActionDesc(Administrateur administrateur);    List<AdminActionLog> findByAdministrateurId(Long adminId);}